mapper.select:
SELECT ch.id, ch.user_id as userId, ch.user_question as userQuestion, ch.ai_answer as aiAnswer, ch.answer_source as answerSource, ch.rating, ch.create_time as createTime, COALESCE(u.nickname, u.username) as userName, COALESCE(u.nickname, u.username) as userNickname, u.avatar as userAvatar FROM chat_history ch LEFT JOIN user u ON ch.user_id = u.id
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR ch.user_question LIKE CONCAT('%', #{keyword}, '%'))
AND ch.answer_source = #{answerSource}
AND ch.rating = #{rating}
ORDER BY ch.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM chat_history ch LEFT JOIN user u ON ch.user_id = u.id
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR ch.user_question LIKE CONCAT('%', #{keyword}, '%'))
AND ch.answer_source = #{answerSource}
AND ch.rating = #{rating}
